const cleanDate = (d) => d ? String(d).replace(/T.*$/, '').replace(/\//g, '-').trim() : '';
const formatWithDay = (d, lang) => {
  if (!d) return ''; 
  const c = cleanDate(d); 
  if (!c) return ''; 
  const parts = c.split('-'); 
  if(parts.length !== 3) return c.substring(2).replace(/-/g, '/'); 
  const dateObj = new Date(parts[0], parts[1]-1, parts[2]); 
  const yy = parts[0].substring(2); const mm = parts[1]; const dd = parts[2];
  const daysZh = ['周日', '周一', '周二', '周三', '周四', '周五', '周六']; 
  const daysEn = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  return `${yy}/${mm}/${dd}, ${lang === 'zh' ? daysZh[dateObj.getDay()] : daysEn[dateObj.getDay()]}`;
};
const shortDate = (d) => { const c = cleanDate(d); return c ? c.substring(2).replace(/-/g, '/') : ''; };
const formatETA = (d, s) => { if (!d || !s || s <= 0) return ''; const h = d / s; if (h < 0.1) return '< 5m'; const hr = Math.floor(h); const m = Math.round((h - hr) * 60); return hr === 0 ? `${m}m` : m === 0 ? `${hr}h` : `${hr}h ${m}m`; };

const formatAMapTime = (secs) => {
    if (!secs) return '';
    const h = Math.floor(secs / 3600);
    const m = Math.floor((secs % 3600) / 60);
    return h > 0 ? `${h}h ${m}m` : `${m}m`;
};

