          const startDate = getVal(['start date', '开始日期', 'date', '日期', 'start']);
          const endDate = getVal(['end date', '结束日期', 'end']) || startDate;
          
          const statusVal = getVal(['status', '状态', '确认']) || '';
          const strStatus = String(statusVal).trim().toLowerCase();
          const isCompleted = strStatus.includes('完成') || strStatus.includes('completed') || strStatus === 'done';
          const isConfirmed = (strStatus.includes('确认') && !strStatus.includes('待确认')) || strStatus.includes('confirmed') || strStatus === 'ok' || strStatus === 'yes' || strStatus === 'true';
          const parsedStatus = isCompleted ? 'Completed' : (isConfirmed ? 'Confirmed' : 'TBC');

          let assignedColor = '#3b82f6';
          if (phaseColors[phase]) { assignedColor = phaseColors[phase]; } 
          else { const paletteIndex = (colorNum - 1) % COLOR_PALETTE.length; assignedColor = COLOR_PALETTE[paletteIndex] || '#3b82f6'; }

