      const origStartParts = clipboard.stop.startDate.split('-');
      const newStartParts = targetDateStr.split('-');
      
      const origStart = new Date(origStartParts[0], origStartParts[1] - 1, origStartParts[2]);
      const newStart = new Date(newStartParts[0], newStartParts[1] - 1, newStartParts[2]);
      
      const diffTime = newStart.getTime() - origStart.getTime();
      const diffDays = Math.round(diffTime / (1000 * 3600 * 24));
      
      const origEndStr = clipboard.stop.endDate || clipboard.stop.startDate;
      const origEndParts = origEndStr.split('-');
      const origEnd = new Date(origEndParts[0], origEndParts[1] - 1, origEndParts[2]);

