                                     <div className="flex items-center gap-3">
                                        <div className="w-5 h-5 rounded-full bg-slate-400 flex items-center justify-center shrink-0"><Home size={10} className="text-white" /></div>
                                        <div className="truncate">
                                          <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{t.returnDest}</p>
                                          <p className="text-xs text-slate-600 font-bold truncate">{phaseReturns[phase].name}</p>
                                        </div>
                                     </div>
                                     {userRole !== 'view' && <button onClick={() => remove(ref(db, `projects/${currentProject}/phaseReturns/${phase}`))} className="p-1.5 text-red-400 hover:bg-red-50 rounded-lg shrink-0"><Trash2 size={14}/></button>}
